817	\begin{definition}[Cover-totality source-object identification, iter-031]
818	  \label{def:Scheme_HModule_prime_top_sourceIso}
819	  \lean{AlgebraicGeometry.Scheme.HModule'_top_sourceIso}
820	  \uses{def:Scheme_HModule_prime}
821	  \leanok
822	  Let $k$ be a field, $C$ a category with morphism universe $u$, $J : \GrothendieckTopology\,C$, $T : C$ a terminal object (witnessed by $h_T : \mathtt{IsTerminal}\,T$), and assume $\HasWeakSheafify\,J\,(\Type\,u)$ and $\HasSheafify\,J\,(\ModuleCat.\{u\}\,k)$. There is a natural isomorphism in $\Sheaf\,J\,(\ModuleCat.\{u\}\,k)$:
823	  \[
824	    (\presheafToSheaf\,J\,\_).\mathrm{obj}\,
825	        ((\yoneda \circ (\Functor.\mathtt{whiskeringRight}\,\_\,\_\,\_).\mathrm{obj}\,(\ModuleCat.\mathtt{free}\,k)).\mathrm{obj}\,T)
826	      \;\cong\;
827	      (\constantSheaf\,J\,(\ModuleCat.\{u\}\,k)).\mathrm{obj}\,(\ModuleCat.\mathrm{of}\,k\,k).
828	  \]
829	\end{definition}
830	
831	\begin{proof}
832	  \leanok
833	  Compose three Mathlib pieces, using the identity $\constantSheaf\,J\,D = \Functor.\mathtt{const}\,C^{\op} \circ \presheafToSheaf\,J\,D$ (\texttt{Mathlib/CategoryTheory/Sites/ConstantSheaf.lean}, line 65):
834	  \begin{enumerate}
835	    \item $\yoneda.\mathrm{obj}\,T \cong (\Functor.\mathtt{const}\,C^{\op}).\mathrm{obj}\,\PUnit$ — the terminal-collapse: at object $X^{\op}$ both presheaves evaluate to a one-element type, with the iso supplied component-wise via $\mathtt{IsTerminal.from}$ for the inverse and $\mathtt{IsTerminal.hom\_ext}$ for the section identity.
836	    \item Whisker right with $(\Functor.\mathtt{whiskeringRight}\,\_\,\_\,\_).\mathrm{obj}\,(\ModuleCat.\mathtt{free}\,k)$, then apply $\Functor.\mathtt{constComp}$ to obtain $((\Functor.\mathtt{const}\,C^{\op}).\mathrm{obj}\,\PUnit) \circ \ModuleCat.\mathtt{free}\,k = (\Functor.\mathtt{const}\,C^{\op}).\mathrm{obj}\,((\ModuleCat.\mathtt{free}\,k).\mathrm{obj}\,\PUnit)$ as an iso.
837	    \item Apply $(\Functor.\mathtt{const}\,C^{\op}).\mathtt{mapIso}$ to the linear-equivalence-derived iso $(\ModuleCat.\mathtt{free}\,k).\mathrm{obj}\,\PUnit \cong \ModuleCat.\mathrm{of}\,k\,k$ (via $\mathtt{Finsupp.LinearEquiv.finsuppUnique}\,k\,k\,\PUnit$ followed by $\mathtt{LinearEquiv.toModuleIso}$).
838	  \end{enumerate}
839	  Apply $(\presheafToSheaf\,J\,\_).\mathtt{mapIso}$ to the composed presheaf-level iso to land in $\Sheaf\,J\,(\ModuleCat.\{u\}\,k)$; the right-hand side then unfolds via the $\constantSheaf$ identity above.
840	\end{proof}
841	
842	\subsection{Use in Serre finiteness}
843	
844	The iter-029 lemmas materialise Step 1 (the abstract LES) and Step 2 (the corner-identification simp lemmas) of the iter-028 Serre-finiteness sketch (Section~\ref{sec:scheme_affineCoverMVSquare}); iter-030 materialised Step 2.5 (the toModuleKSheaf specialisation, a routine binding so downstream code paths can reference the LES on the structure sheaf of a curve directly); iter-031 (this iteration) materialises the \emph{source-object} half of Step 3 (the cover-totality identification, leaving the Ext-transport step plus universe handling to iter-032+). The remaining work — Step 3-rest (the LinearEquiv on cohomology $\HModulePrime\,k\,F\,n\,T \equiv_{\Module k} \HModule\,k\,F\,n$ for terminal $T$, with universe lift), Step 4 (affine vanishing $H^{>0}(\Spec A, \mathcal F) = 0$, possibly multi-iteration depending on Mathlib state), and Step 5 (finiteness of each $H^0$ piece, hence of $H^1(C, \mathcal O_C)$) — is iter-032+.
